3	namespace App\Http\Controllers\Api;
4	
5	use App\Http\Controllers\Controller;
6	use App\Services\WaitlistService;
7	use Illuminate\Http\JsonResponse;
8	use Illuminate\Http\Request;
9	use Illuminate\Validation\Rule;
10	use Symfony\Component\HttpFoundation\Response;
11	
12	class WaitlistController extends Controller
13	{
14	    public function __construct(
15	        private readonly WaitlistService $waitlistService,
16	    ) {
17	    }
18	
19	    public function index(Request $request): JsonResponse
20	    {
21	        $actor = $request->user();
22	
23	        if (! in_array($actor->role, ['staff', 'administrator'], true)) {
24	            return $this->error('FORBIDDEN', Response::HTTP_FORBIDDEN);
25	        }
26	
27	        $validated = $request->validate([
28	            'per_page' => ['nullable', 'integer', 'min:1', 'max:100'],
29	            'page' => ['nullable', 'integer', 'min:1'],
30	        ]);
31	
32	        $perPage = (int) ($validated['per_page'] ?? 20);
33	        $page = (int) ($request->input('page', 1));
34	
35	        $departmentId = $actor->role === 'staff' ? (int) $actor->department_id : null;
36	        $paginator = $this->waitlistService->listForSite(
37	            $actor->role === 'administrator' ? null : $actor->site_id,
38	            $departmentId,
39	            $perPage,
40	            $page,
41	        );
42	
43	        return response()->json([
44	            'success' => true,
45	            'data' => [
46	                'data' => $paginator->items(),
47	                'current_page' => $paginator->currentPage(),
48	                'per_page' => $paginator->perPage(),
49	                'total' => $paginator->total(),
50	                'last_page' => $paginator->lastPage(),
51	            ],
52	        ]);
53	    }
54	
55	    public function store(Request $request): JsonResponse
56	    {
57	        $actor = $request->user();
58	
59	        if (! in_array($actor->role, ['staff', 'administrator'], true)) {
60	            return $this->error('FORBIDDEN', Response::HTTP_FORBIDDEN);
61	        }
62	
63	        $siteId = (int) ($request->input('_site_id') ?? $actor->site_id);
64	
65	        $validated = $request->validate([
66	            'client_id' => ['required', 'integer', Rule::exists('users', 'id')->where('site_id', $siteId)],
67	            'service_type' => ['required', 'string', 'max:100'],
68	            'priority' => ['required', 'integer', 'min:1', 'max:9999'],
69	            'preferred_start' => ['required', 'date'],
70	            'preferred_end' => ['required', 'date', 'after:preferred_start'],
71	            'department_id' => ['nullable', 'integer', Rule::exists('departments', 'id')->where('site_id', $siteId)],
72	        ]);
73	
74	        if ($actor->role === 'staff') {
75	            $requestedDepartment = (int) ($validated['department_id'] ?? $actor->department_id);
76	            if ($requestedDepartment !== (int) $actor->department_id) {
77	                return $this->error('FORBIDDEN', Response::HTTP_FORBIDDEN);
78	            }
79	            $validated['department_id'] = $requestedDepartment;
80	        }
81	
82	        $validated['site_id'] = $siteId;
83	
84	        $entry = $this->waitlistService->addToWaitlist($validated, $actor);
85	
86	        return response()->json([
87	            'success' => true,
88	            'data' => [
89	                'waitlist' => $entry,
90	            ],
91	        ], Response::HTTP_CREATED);
92	    }
93	
94	    public function confirmBackfill(Request $request, int $id): JsonResponse
95	    {
96	        $actor = $request->user();
97	
98	        if (! in_array($actor->role, ['staff', 'administrator'], true)) {
99	            return $this->error('FORBIDDEN', Response::HTTP_FORBIDDEN);
100	        }
101	
102	        $validated = $request->validate([
103	            'provider_id' => ['required', 'integer', 'exists:users,id'],
104	            'resource_id' => ['required', 'integer', 'exists:resources,id'],
105	            'department_id' => ['required', 'integer', 'exists:departments,id'],
106	            'start_time' => ['required', 'date'],
107	            'end_time' => ['required', 'date', 'after:start_time'],
108	        ]);
109	
110	        if ($actor->role === 'staff' && (int) $validated['department_id'] !== (int) $actor->department_id) {
111	            return $this->error('FORBIDDEN', Response::HTTP_FORBIDDEN);
112	        }
113	
114	        $result = $this->waitlistService->confirmBackfill($id, $validated, $actor);
115	
116	        return response()->json([
117	            'success' => $result['success'],
118	            'error' => $result['success'] ? null : ($result['error'] ?? null),
119	            'data' => $result['data'] ?? [],
120	        ], (int) ($result['status'] ?? 200));
121	    }
122	
123	    public function destroy(Request $request, int $id): JsonResponse
124	    {
125	        $actor = $request->user();
126	
127	        if (! in_array($actor->role, ['staff', 'administrator'], true)) {
128	            return $this->error('FORBIDDEN', Response::HTTP_FORBIDDEN);
129	        }
130	
131	        $result = $this->waitlistService->removeWaitingEntry($id, $actor);
132	
133	        return response()->json([
134	            'success' => $result['success'],
135	            'error' => $result['success'] ? null : ($result['error'] ?? null),
136	            'data' => $result['data'] ?? [],
137	        ], (int) ($result['status'] ?? 200));
138	    }
139	
140	    private function error(string $code, int $status, array $data = []): JsonResponse
141	    {
142	        return response()->json([
143	            'success' => false,
144	            'error' => $code,
145	            'data' => $data,
146	        ], $status);
147	    }
148	}
