32	
33	        $user->forceFill([
34	            'password_hash' => Hash::make($validated['new_password']),
35	        ])->save();
36	
37	        AuditLogger::write(
38	            $actor->id,
39	            'PASSWORD_RESET',
40	            User::class,
41	            $user->id,
42	            ['verification_note' => $validated['verification_note']],
43	            $request->ip(),
44	        );
45	
46	        return response()->json([
47	            'success' => true,
48	            'data' => ['message' => 'Password reset successful'],
49	        ]);
50	    }
51	}
